const express = require('express');
const mongoose = require('mongoose');
const cors = require('cors');
require('dotenv').config();

const app = express();
app.use(express.json());
app.use(cors());

// Use the exact DB name you requested
const mongoURI = "mongodb://localhost:27017/ELAFABDU1282025";

mongoose.connect(mongoURI)
    .then(() => console.log("✅ MONGO LINKED: ELAFABDU1282025"))
    .catch(err => console.error("❌ CONNECTION ERROR:", err));

// Schema for the Registry
const UserSchema = new mongoose.Schema({
    username: String,
    email: String,
    date: { type: Date, default: Date.now }
});
const User = mongoose.model('User', UserSchema);

// --- ROUTES ---

// Register User
app.post('/api/register', async (req, res) => {
    try {
        const newUser = new User(req.body);
        await newUser.save();
        res.status(201).json({ success: true, message: "User Saved to DB" });
    } catch (err) {
        res.status(500).json({ success: false, error: err.message });
    }
});

// Get All Users
app.get('/api/users', async (req, res) => {
    const users = await User.find();
    res.json(users);
});

const PORT = 5000;
app.listen(PORT, () => {
    console.log(`🚀 SECURE SERVER RUNNING ON PORT ${PORT}`);
});